var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"어엉? 모르스? 뭐야, 그 이상한 이름은?","JPN":"ああん？　モールス？　なんだ、その変な名前は。","ENG":"What? Mors? What kind of name is that?","TWN":"什麼？莫爾斯？這是什麼奇怪的名字？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그것보다 너도 용병이냐? 이번 의뢰에 사람이 비는데 같이 갈래?","JPN":"それよりお前も傭兵なのか？　今度の依頼、席空いてるけど一緒に行くか？","ENG":"Hey, you a mercenary, too? There’s room for another on this commission, want to come along?","TWN":"不過你也是傭兵嗎？這次的委託人不夠，你要一起去嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"아……. 모르스. 기억하지. 요즘에야 뭐 별난 놈들이 많아서 묻히긴 했는데, 옛날엔 유명했지.","JPN":"あ……モールス。覚えてるよ。最近はまあ、変な奴らが多くて埋もれているけど、昔は有名だったな。","ENG":"Oh... Mors. I remember now! There're a lot of weirdos around now these days, but back in the day that name was pretty famous.","TWN":"喔……莫爾斯我有印象，可能最近奇怪的傢伙太多，所以大家有點忘記她，但以前是很有名的！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"가는 곳마다 재앙을 부른다던 녀석인데……. 솔직히 이 바닥 소문은 부풀려지기 마련이거든.","JPN":"行くところに災いを呼ぶ奴ってことだけど……正直ここんとこの噂って盛りすぎること多いだろ。","ENG":"Word is, anywhere she goes, disaster follows. Ehh, it’s probably just some rumor though, you know how those are.","TWN":"據說她所到之處就會引發災難……不過像這種傳言，都是誇大的成分居多啦！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"아마 그냥 남들보다 좀 튀는 차림새에다 눈치 없이 이거저거 건드려서 그랬던 거 아닐까?","JPN":"たぶん他の奴より目立つ恰好で、あちらこちらを騒がせたからじゃないかね？","ENG":"It’s probably just because she looks so different than everyone else she gets noticed so often.","TWN":"或許她只是穿著比別人顯眼，然後又喜歡到處惹事生非，大家才會對她特別有印象吧？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"모르스라…….","JPN":"モールスか……","ENG":"Mors...","TWN":"莫爾斯……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"최근 어떤 손님에게서 비슷한 사람을 봤다는 이야기를 들은 적 있어.","JPN":"最近あるお客さんに、似たような人を見たって聞いたことがあるわ。","ENG":"Huh, I heard the other day from a customer that they saw someone fitting that description.","TWN":"我最近是有聽某位客人說，他有看到類似的人物。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"계약?","JPN":"契約？","ENG":"A contract?","TWN":"契約？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"아니, 그렇게까지 대단한 정보는 또 아니거든.","JPN":"いや、そこまで大した情報ではないのよね。","ENG":"Nah. It wasn’t that much info.","TWN":"拜託，這又不是什麼厲害的消息。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"무슨 이유인지 몰라도 꼭 찾길 바랄게. 아가씨.","JPN":"理由はわからないけど見つかったらいいな。お嬢さん。","ENG":"Don’t know what you’re looking for, but I hope you find it, Lady!","TWN":"雖然不知道你為何要找她，但祝你早日找到她囉，小姐。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_GIRL","text":{"KOREA":"……북방 합의체의 세력권에 숨어 있을 줄은 몰랐어.","JPN":"……北方合意体の縄張りに隠れてるとは思ってもいなかった。","ENG":"...Didn’t expect her to be hiding in the Northern Union’s sphere of influence.","TWN":"……沒想到你會躲在北方和議會的勢力範圍內。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_GIRL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L24_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_GIRL","text":{"KOREA":"이성이 오락가락하는 그림자치고는 머리를 좀 굴렸군. 모르스.","JPN":"理性が曖昧なシャドウにしてはよく考えたな。モールス。","ENG":"You really put your brain to work though you’re a Shadow, didn’t you? Mors.","TWN":"以腦袋不清楚的暗影來說，你算是有在動腦的，莫爾斯。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"나를 찾아온 것인가. 소녀여.","JPN":"我を訪ねて来たのか。少女よ。","ENG":"You came seeking me, girl?","TWN":"少女，你是來找我的嗎？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"용무는 듣지 않겠다. 이곳은 위험하니 어서 떠나라.","JPN":"用件は聞かぬ。ここは危ない、速やかにここを離れろ。","ENG":"It doesn’t matter what carries you here. This place is dangerous. You should leave.","TWN":"我不管你為何來找我，這個地方很危險，你快離開吧。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_GIRL","text":{"KOREA":"인간 따위를 걱정해 주니 그런 꼴이 되었다고 생각하지 않아?","JPN":"人間なんかを心配するからそんな様になったとは思わないのか？","ENG":"Don’t you think you ended up in such a miserable state because you care so much about humans?","TWN":"你不覺得，就是因為你太替人類著想，才會落得這般下場嗎？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_GIRL","text":{"KOREA":"미니스트라라는 개체가 발생할 때도. 언변이 부족하면 행동으로라도 강제했어야지.","JPN":"ミニストラという個体が発生した時も。言葉で足りないなら強行すべきだった。","ENG":"Even when Ministra came into existence. If you aren’t that great a speaker you should have spoken with your actions.","TWN":"迷你斯特拉這個個體產生時也是，就算口才不好，起碼也要強制行動吧？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"나에 대해 많은 것을 알고 있군. 누구에게 그 일화를 들은 것인가.","JPN":"我についてよく知っているな。誰からそれを聞いたのだ。","ENG":"You seem to know much about me. From whom, did you hear that?","TWN":"看來你知道許多關於我的事，這些都是誰告訴你的？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_GIRL","text":{"KOREA":"우리 조직은 정보력으로 관리국에 밀리지 않아.","JPN":"我々の組織の情報力は管理局に劣らないからな。","ENG":"Let’s just say that our organization isn’t that far behind the Administration when it comes to information.","TWN":"我們組織的情報能力可不輸管理局。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_GIRL","text":{"KOREA":"지금 같은 허울뿐인 관리국이 아니라, <color=#ffd34c>진짜</color> 관리국 말이지.","JPN":"今のように上辺だけの管理局ではなく、<color=#ffd34c>本物</color>の管理局のね。","ENG":"Well. It’s not quite the same as the bogus Administration now, it’s the <color=#ffd34c>real</color> Administration.","TWN":"我不是指現在這個虛有其名的管理局，是<color=#ffd34c>真正的</color> 管理局。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……구 관리국의 생존자였나?","JPN":"……旧管理局の生き残りであったか？","ENG":"...You are a survivor of the Old Administration?","TWN":"……你是舊管理局的倖存者嗎？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그렇다면 더더욱 이해할 수 없군. 그대들에게 나는 쫓아내야 할 불청객일 터.","JPN":"それならなおさら理解できん。そなたらにとって我は追い出すべき、招かれざる客であろう。","ENG":"Then it is all the more incomprehensible. I am not a welcome guest to them.","TWN":"若是如此，那我就更不明白了，對你們而言，我應該是不速之客吧？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"어찌하여 사람의 발길이 닿지 않는 이 오지에 홀로 방문한 것인가.","JPN":"なぜ人の足の届かないこの奥地まで一人で来たのだ。","ENG":"And for what reason have you come all this way alone?","TWN":"為什麼會一個人來這個人煙罕至的地方找我？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_GIRL","text":{"KOREA":"네 힘이 필요하다. 모르스.","JPN":"あなたの力が必要だ。モールス。","ENG":"Your help is needed, Mors.","TWN":"莫爾斯，我需要你的能力。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_GIRL","text":{"KOREA":"마에스트로는 요격되지 않았어. 아직 버젓이 존재하고 있지.","JPN":"マエストロは迎撃されなかった。いまだに存在している。","ENG":"Maestra was never truly defeated. She still lives.","TWN":"我們未能成功攔截指揮家，她現在還存在這個世界上。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"마에스트로……? 지금 마에스트로라고 하였는가?","JPN":"マエストロ……？　今マエストロと言ったか？","ENG":"Maestra...? Did you say Maestra?","TWN":"指揮家……？你剛是說指揮家嗎？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_GIRL","text":{"KOREA":"그래. 핵이 파괴되었지만, 완전히 소멸하기 전에 이 세계로 넘어왔다.","JPN":"そう。核は破壊されたが、完全に消滅する前にこっちの世界に渡ってきたんだ。","ENG":"That’s right. Her core was destroyed, but she managed to get to this world before it completely vanished.","TWN":"沒錯，雖然核心已經遭到破壞，但她趁還沒有完全消滅之前，又跑到這個世界來。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_GIRL","text":{"KOREA":"녀석은 다시 연주할 시기를 기다리고 있어. 인간의 허물로 위장한 채.","JPN":"奴は再び演奏する時期を待っている。人間の皮で偽装したまま。","ENG":"She’s waiting for her chance to begin performing again, disguised as a regular human being.","TWN":"她偽裝成人，伺機等候演奏的機會再次到來。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……그렇다면, 내 힘은 너에게 아무런 가치도 없을 것이다.","JPN":"……それなら、我の力はそなたに何の価値もあるまい。","ENG":"If so, my power will be of no use to you.","TWN":"……若真如你所言，那我恐怕幫不上忙。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"갑주에 의지하고 있을 뿐, 나는 이미 모든 것을 소진해 버린 빈껍데기에 불과할지니.","JPN":"甲冑に頼っているばかりで、我はすでに全てを使い切った抜け殻に過ぎん。","ENG":"I rely on my armor for my strength. I am no more than an old vessel.","TWN":"我有的就是這身鎧甲，而我現在不過就是個虛有其表的空殼子。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_GIRL","text":{"KOREA":"마에스트로 역시 마찬가지다.","JPN":"マエストロも同じだ。","ENG":"The same is true for Maestra.","TWN":"指揮家也是如此。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_GIRL","text":{"KOREA":"현실세계에서 20년 남짓한 시간을 보낸 것만으로는, 핵이 파괴될 정도의 중상을 완전히 회복할 수 없어.","JPN":"現実世界で20年あまりの時を過ごしただけでは、核が破壊されるくらいの重傷から完全に回復することはできない。","ENG":"Spending 20 years or so alone on the Normalside could not have completely restored her core.","TWN":"光是在現實世界生活超過20年，是無法完全恢復核心的狀態的。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_GIRL","text":{"KOREA":"단원들이 집결하기 전에 죽인다. 그거라면 너와 우리들만으로 충분해.","JPN":"団員が集結する前に殺す。それならあなたと我々だけで十分だ。","ENG":"We're going to kill her before other members all gather. My organization and you working together are enough for that.","TWN":"必須趁她召集團員之前除掉她！而這件事只需要我們加上你就能夠完成。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이름을 고하라, 소녀여.","JPN":"名を告げろ、少女よ。","ENG":"Speak your name, girl.","TWN":"少女，報上名來。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_GIRL","text":{"KOREA":"피오 바르거스. 구 관리국 시절의 식별명은…….","JPN":"ピオ・バルガス。旧管理局時代の識別名は……","ENG":"Pio Vargus. The name I go by in the Old Administration is...","TWN":"我叫妃歐·巴克斯，在舊管理局的識別名稱是……"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"카르데나스 부전대장, 몽타뉴다.","JPN":"カルデナス副戦隊長、モンターニュだ。","ENG":"Cardenas Deputy Commander, Montagne.","TWN":"卡特納斯副戰隊長，蒙塔妮。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};